import React, { Fragment } from 'react';

const Home = ({ setAuth }) => {
  const handleLogout = () => {
    // Call setAuth with false to indicate user logout
    setAuth(false);
  };

  return (
    <Fragment>
      <h1>Home</h1>
      <button onClick={handleLogout}>Log out</button>
    </Fragment>
  );
};

export default Home;
